<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Dashboard — Reconix</title>
  <link rel="preconnect" href="https://fonts.googleapis.com">
  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
  <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;600;700&family=DM+Sans:wght@400;500;600&family=DM+Mono:wght@400;500;600&display=swap" rel="stylesheet">
  <style>
    /* ── Design System Tokens ─────────────────────────────────────── */
    :root {
      --bg-0:      #fafbfc;
      --bg-1:      #f1f5f9;
      --bg-tint:   #faf9ff;
      --tx-1:      #0f172a;
      --tx-2:      #475569;
      --tx-3:      #94a3b8;
      --border:    #e2e8f0;
      --border-h:  #cbd5e1;
      --purple:    #7c3aed;
      --purple-bg: #f3e8ff;
      --red:       #dc2626;
      --red-bg:    #fef2f2;
      --amber:     #d97706;
      --amber-bg:  #fffbeb;
      --green:     #059669;
      --green-bg:  #ecfdf5;
      --font-h: "Plus Jakarta Sans", system-ui, sans-serif;
      --font-b: "DM Sans", system-ui, sans-serif;
      --font-m: "DM Mono", ui-monospace, monospace;
    }
    [data-theme="dark"] {
      --bg-0:     #0b1019;
      --bg-1:     #0f172a;
      --bg-tint:  #19132e;
      --tx-1:     #f8fafc;
      --tx-2:     #94a3b8;
      --tx-3:     #64748b;
      --border:   #1e293b;
      --border-h: #334155;
      --red:      #f87171;
      --red-bg:   #3a1a1a;
      --amber:    #fbbf24;
      --amber-bg: #3a2d1a;
      --green:    #34d399;
      --green-bg: #1a3a30;
    }

    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    html { -webkit-font-smoothing: antialiased; -moz-osx-font-smoothing: grayscale; }
    body {
      display: grid;
      grid-template-rows: 60px 1fr auto;
      min-height: 100vh;
      background: var(--bg-0);
      color: var(--tx-1);
      font-family: var(--font-b);
      font-size: 15px;
      line-height: 1.6;
      transition: background-color 200ms ease-out, color 200ms ease-out;
    }

    /* ── TopNav ───────────────────────────────────────────────────── */
    .topnav {
      height: 60px;
      display: flex;
      align-items: center;
      padding: 0 clamp(16px, 4vw, 56px);
      background: var(--bg-0);
      border-bottom: 1px solid var(--border);
      gap: 6px;
      transition: background-color 200ms ease-out, border-color 200ms ease-out;
    }
    .wordmark {
      font-family: var(--font-m);
      font-size: 13px;
      font-weight: 600;
      letter-spacing: 0.15em;
      text-transform: uppercase;
      color: var(--tx-1);
      text-decoration: none;
      margin-right: 6px;
      transition: color 150ms ease-out;
    }
    .wordmark:hover { color: var(--tx-2); }

    .nav-details { position: relative; }
    .nav-details > summary {
      list-style: none;
      cursor: pointer;
      display: inline-flex;
      align-items: center;
      gap: 5px;
      padding: 4px 9px;
      border: 1px solid var(--border);
      border-radius: 6px;
      font-family: var(--font-b);
      font-size: 14px;
      color: var(--tx-1);
      user-select: none;
      transition: border-color 150ms ease-out, background-color 150ms ease-out;
    }
    .nav-details > summary::-webkit-details-marker { display: none; }
    .nav-details > summary:hover,
    .nav-details[open] > summary { border-color: var(--border-h); background: var(--bg-1); }
    .persona-summary {
      font-family: var(--font-m) !important;
      font-size: 12px !important;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      padding: 4px 8px !important;
    }
    .crit-dot {
      width: 6px; height: 6px;
      border-radius: 50%;
      background: var(--red);
      flex-shrink: 0;
    }
    .nav-dropdown {
      position: absolute;
      top: calc(100% + 6px);
      left: 0;
      min-width: 172px;
      background: var(--bg-0);
      border: 1px solid var(--border-h);
      border-radius: 8px;
      padding: 4px;
      z-index: 200;
    }
    .nav-dropdown a, .nav-dropdown button {
      display: block;
      width: 100%;
      text-align: left;
      padding: 7px 10px;
      font-family: var(--font-b);
      font-size: 13px;
      color: var(--tx-1);
      text-decoration: none;
      border-radius: 4px;
      border: none;
      background: none;
      cursor: pointer;
      transition: background-color 150ms ease-out;
    }
    .nav-dropdown a:hover, .nav-dropdown button:hover { background: var(--bg-1); }
    .nav-dropdown-right { left: auto; right: 0; }
    .topnav-spacer { flex: 1; }
    .avatar {
      width: 26px; height: 26px;
      border-radius: 50%;
      background: var(--bg-1);
      border: 1px solid var(--border);
      display: inline-flex;
      align-items: center;
      justify-content: center;
      font-family: var(--font-m);
      font-size: 10px;
      font-weight: 600;
      color: var(--tx-2);
    }
    .chevron-glyph { color: var(--tx-3); font-size: 11px; }

    /* ── Page wrapper ─────────────────────────────────────────────── */
    .page {
      max-width: 1280px;
      margin: 0 auto;
      width: 100%;
      padding: 0 clamp(16px, 4vw, 56px);
    }
    .hairline { border: none; border-top: 1px solid var(--border); }

    /* ── Masthead ─────────────────────────────────────────────────── */
    .masthead {
      padding: 36px 0 32px;
      display: grid;
      grid-template-columns: 1fr auto;
      gap: 8px 32px;
      align-items: start;
      min-height: 120px;
    }
    .masthead-title-row {
      display: flex;
      align-items: baseline;
      gap: 14px;
      flex-wrap: wrap;
    }
    .masthead-title {
      font-family: var(--font-h);
      font-size: 34px;
      font-weight: 600;
      line-height: 1.15;
      letter-spacing: -0.015em;
      color: var(--tx-1);
    }
    .masthead-fp {
      font-family: var(--font-m);
      font-size: 11px;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      color: var(--tx-3);
    }
    .masthead-sub {
      margin-top: 6px;
      font-family: var(--font-b);
      font-size: 15px;
      color: var(--tx-2);
    }
    .masthead-right {
      display: flex;
      flex-direction: column;
      align-items: flex-end;
      gap: 10px;
      padding-top: 8px;
    }
    .refresh-label {
      font-family: var(--font-m);
      font-size: 11px;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      color: var(--tx-3);
    }
    .btn-primary {
      background: var(--purple);
      color: #fff;
      font-family: var(--font-b);
      font-size: 14px;
      font-weight: 600;
      padding: 8px 16px;
      border-radius: 6px;
      border: none;
      cursor: pointer;
      text-decoration: none;
      display: inline-block;
      transition: background-color 150ms ease-out;
    }
    .btn-primary:hover { background: #6d28d9; }

    /* ── Block header ─────────────────────────────────────────────── */
    .block-head { display: flex; align-items: baseline; gap: 12px; flex-wrap: wrap; }
    .block-title {
      font-family: var(--font-h);
      font-size: 22px;
      font-weight: 600;
      letter-spacing: -0.01em;
      color: var(--tx-1);
    }
    .block-meta {
      font-family: var(--font-m);
      font-size: 11px;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      color: var(--tx-3);
    }
    .block-intro {
      font-family: var(--font-b);
      font-size: 14px;
      color: var(--tx-2);
      margin-top: 3px;
      margin-bottom: 20px;
    }

    /* ── Severity pills ───────────────────────────────────────────── */
    .pill {
      display: inline-flex;
      align-items: center;
      gap: 3px;
      font-family: var(--font-m);
      font-size: 11px;
      font-weight: 500;
      letter-spacing: 0.06em;
      text-transform: uppercase;
      padding: 2px 5px;
      border-radius: 3px;
      white-space: nowrap;
      flex-shrink: 0;
    }
    .pill-high { color: var(--red);   background: var(--red-bg);   }
    .pill-med  { color: var(--amber); background: var(--amber-bg); }
    .pill-low  { color: var(--tx-2);  background: var(--bg-1);     }
    .pill-ok   { color: var(--green); background: var(--green-bg); }

    /* ── ActionQueue ──────────────────────────────────────────────── */
    .aq-block { padding: 48px 0; }
    .aq-list  { display: flex; flex-direction: column; gap: 6px; }

    details.aq-row {
      border: 1px solid var(--border);
      border-radius: 8px;
      overflow: hidden;
      transition: border-color 150ms ease-out;
    }
    details.aq-row:hover { border-color: var(--border-h); }
    details.aq-row > summary {
      list-style: none;
      display: flex;
      align-items: center;
      min-height: 72px;
      cursor: pointer;
      user-select: none;
    }
    details.aq-row > summary::-webkit-details-marker { display: none; }

    .aq-high > summary { background: color-mix(in srgb, var(--red-bg)   7%, var(--bg-0)); }
    .aq-med  > summary { background: color-mix(in srgb, var(--amber-bg) 7%, var(--bg-0)); }
    .aq-low  > summary { background: var(--bg-0); }

    .aq-stripe { width: 3px; align-self: stretch; flex-shrink: 0; }
    .aq-high .aq-stripe { background: var(--red);   }
    .aq-med  .aq-stripe { background: var(--amber); }
    .aq-low  .aq-stripe { background: transparent;  }

    .aq-content {
      flex: 1;
      padding: 14px 16px;
      display: flex;
      flex-direction: column;
      gap: 5px;
      min-width: 0;
    }
    .aq-top    { display: flex; align-items: center; gap: 9px; flex-wrap: wrap; }
    .aq-headline {
      font-family: var(--font-b);
      font-size: 15px;
      font-weight: 600;
      color: var(--tx-1);
    }
    .aq-body-text {
      font-family: var(--font-b);
      font-size: 13.5px;
      color: var(--tx-2);
    }
    .aq-pills { display: flex; gap: 5px; flex-wrap: wrap; align-items: center; }
    .domain-pill {
      font-family: var(--font-m);
      font-size: 11px;
      letter-spacing: 0.03em;
      color: var(--tx-2);
      border: 1px solid var(--border);
      border-radius: 3px;
      padding: 1px 6px;
      text-decoration: none;
      transition: border-color 150ms ease-out, color 150ms ease-out;
    }
    .domain-pill:hover { border-color: var(--border-h); color: var(--tx-1); }

    .aq-actions {
      display: flex;
      align-items: center;
      gap: 6px;
      padding: 14px 16px;
      flex-shrink: 0;
    }
    .chevron-btn {
      background: none;
      border: none;
      cursor: pointer;
      color: var(--tx-3);
      font-family: var(--font-m);
      font-size: 13px;
      padding: 4px 6px;
      border-radius: 4px;
      line-height: 1;
      transition: color 150ms ease-out, background-color 150ms ease-out, transform 150ms ease-out;
    }
    .chevron-btn:hover { color: var(--tx-1); background: var(--bg-1); }
    details.aq-row[open] .chevron-btn { transform: rotate(180deg); }

    .btn-review {
      font-family: var(--font-h);
      font-size: 12px;
      font-weight: 600;
      color: var(--tx-1);
      border: 1px solid var(--border);
      border-radius: 6px;
      padding: 6px 12px;
      text-decoration: none;
      background: var(--bg-0);
      white-space: nowrap;
      transition: border-color 150ms ease-out, background-color 150ms ease-out;
    }
    .btn-review:hover { border-color: var(--border-h); background: var(--bg-1); }

    .aq-peek {
      padding: 14px 16px 16px 19px;
      border-top: 1px solid var(--border);
      background: var(--bg-1);
    }
    .peek-label {
      font-family: var(--font-m);
      font-size: 10px;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      color: var(--tx-3);
      margin-bottom: 8px;
    }
    .peek-row {
      display: flex;
      align-items: baseline;
      gap: 8px;
      padding: 3px 0;
      font-family: var(--font-b);
      font-size: 13px;
      color: var(--tx-2);
    }
    .peek-row strong { font-weight: 600; color: var(--tx-1); }
    .peek-note { font-family: var(--font-b); font-size: 12px; color: var(--tx-3); margin-top: 6px; }

    details.show-more { margin-top: 8px; }
    details.show-more > summary {
      list-style: none;
      cursor: pointer;
      font-family: var(--font-b);
      font-size: 13px;
      color: var(--tx-2);
      padding: 8px 2px;
      user-select: none;
      transition: color 150ms ease-out;
